async function syncBookingsByBookingSns(shopId, bookingSns, options = {}) {
  try {
    const syncOptions = {
      includeTracking: false,
      // Default: webhook sync (tanpa tracking)
      ...options
    };
    console.info(`[BookingSync] Memulai sinkronisasi booking spesifik untuk shopId: ${shopId}, bookings: ${bookingSns.length} (includeTracking: ${syncOptions.includeTracking})`);
    if (!bookingSns || bookingSns.length === 0) {
      return {
        success: true,
        data: {
          total: 0,
          processed: 0,
          bookingSns: []
        }
      };
    }
    let processedCount = 0;
    const processedBookings = [];
    const totalBookings = bookingSns.length;
    if (options.onProgress) {
      options.onProgress({
        current: 0,
        total: totalBookings
      });
    }
    const BATCH_SIZE = 20;
    for (let i2 = 0; i2 < bookingSns.length; i2 += BATCH_SIZE) {
      const bookingBatch = bookingSns.slice(i2, i2 + BATCH_SIZE);
      const results = syncOptions.includeTracking ? await processBookingDetailsWithTracking(shopId, bookingBatch) : await processBookingDetails(shopId, bookingBatch);
      results.forEach((result) => {
        if (result.success) {
          processedCount++;
          processedBookings.push(result.bookingSn);
        }
      });
      if (options.onProgress) {
        options.onProgress({
          current: processedCount,
          total: totalBookings
        });
      }
    }
    console.info(`[BookingSync] Selesai sinkronisasi booking spesifik untuk shopId: ${shopId}. Processed: ${processedCount}/${totalBookings}`);
    return {
      success: true,
      data: {
        total: totalBookings,
        processed: processedCount,
        bookingSns: processedBookings
      }
    };
  } catch (error) {
    console.error(`[BookingSync] Error sinkronisasi booking spesifik untuk shopId: ${shopId}:`, error);
    if (options.onError) {
      options.onError(error instanceof Error ? error.message : "Unknown error");
    }
    return {
      success: false,
      error: error instanceof Error ? error.message : "Terjadi kesalahan yang tidak diketahui"
    };
  }
}

